const msg = $input.first().json.message;
const text = (msg.text || '').trim();
const chatId = msg.chat.id;
const staticData = $getWorkflowStaticData('global');
const estado = staticData[String(chatId)]?.estado;

// ── COMANDO: facturas ──
if (text.toLowerCase() === 'facturas') {
  return [{ json: {
    _action: 'ERROR',
    chatId,
    message: '📊 *Consulta tus facturas:*\n\n[Ver Google Sheets](https://docs.google.com/spreadsheets/d/YOUR_GOOGLE_SHEET_ID/edit)'
  }}];
}

// ── CASO 1: Responde SI ──
if (text.toUpperCase() === 'SI' && estado === 'WAITING_CONFIRM') {
  const factura = staticData[String(chatId)].factura;
  delete staticData[String(chatId)];
  // _action: 'CONFIRMAR' va AL FINAL para no ser sobreescrito por ...factura
  return [{ json: { chatId, ...factura, _action: 'CONFIRMAR' } }];
}

// ── CASO 2: Responde NO ──
if (text.toUpperCase() === 'NO' && estado === 'WAITING_CONFIRM') {
  delete staticData[String(chatId)];
  return [{ json: { _action: 'CANCELAR', chatId } }];
}

// ── CASO 3: Nueva factura ──
const splitRegex = /(?:primera|segunda|tercera|cuarta|quinta|sexta|septima|séptima|octava|novena|decima|décima|1a|2a|3a|4a|5a|1ª|2ª|3ª|factura\s*\d+)\s*:?/gi;
const parts = text.split(splitRegex).filter(p => p.trim().length > 0);
const bloques = parts.length > 0 ? parts : [text];

const errorMsg = `❌ No he podido leer los datos de la factura.

📋 *Ejemplo de mensaje:*

Cliente Restaurante ABC S.L.
NIF B12345678
Dirección Calle Mayor 10, Barcelona
Concepto Cena de empresa
12 comensales
Importe total 420
Fecha 28/02/2026
Pago Transferencia

💡 *Para el precio (IVA incluido):*
- *Importe total 420* → divide entre comensales
- *Precio persona 35* → multiplica por comensales

ℹ️ Los dos puntos son opcionales

➕ *Varias facturas:*
Primera
(campos...)
Segunda
(campos...)`;

const get = (block, keys) => {
  for (const key of keys) {
    const escaped = key.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const m = block.match(new RegExp('^[ \\t]*' + escaped + '[ \\t]*:?[ \\t]*(.+)', 'im'));
    if (m && m[1].trim()) return m[1].trim();
  }
  return '';
};

const getPersonas = (block) => {
  const keys = [
    'Personas','Num personas','Número personas','Numero personas','Número de personas',
    'Comensales','Num comensales','Número comensales','Numero comensales','Número de comensales',
    'Pax','Invitados','Asistentes','Num asistentes','Número asistentes',
    'Numero asistentes','Número de asistentes',
    'Clientes','Num clientes','Número clientes',
    'Cubiertos','Plazas','Reserva para','Grupo de','Cantidad'
  ];
  const standard = get(block, keys);
  if (standard) {
    const num = parseInt(standard);
    if (num > 0) return num;
  }
  const reverseKeys = [
    'personas','comensales','pax','invitados','asistentes',
    'clientes','cubiertos','plazas','menus','menús'
  ];
  for (const key of reverseKeys) {
    const m = block.match(new RegExp('^[ \\t]*(\\d+)\\s+' + key, 'im'));
    if (m) return parseInt(m[1]);
  }
  return 0;
};

const cleanNumber = (str) => {
  if (!str) return 0;
  let cleaned = str
    .replace(/€/g, '')
    .replace(/\s/g, '')
    .replace(/\.+$/, '')
    .trim();
  if (/^\d{1,3}(\.\d{3})+(,\d+)?$/.test(cleaned)) {
    cleaned = cleaned.replace(/\./g, '').replace(',', '.');
  } else if (/,\d{1,2}$/.test(cleaned)) {
    cleaned = cleaned.replace(',', '.');
  }
  const dotParts = cleaned.split('.');
  if (dotParts.length > 2) {
    const last = dotParts.pop();
    cleaned = dotParts.join('') + '.' + last;
  }
  return parseFloat(cleaned) || 0;
};

const facturas = [];
const now = new Date();

bloques.forEach((block) => {

  const cliente = get(block, [
    'Cliente','Nombre cliente','Nombre del cliente',
    'Razon social','Razón social','Empresa',
    'Nombre empresa','Nombre de la empresa',
    'Facturar a','A nombre de','Nombre',
    'Sociedad','Compañia','Compañía'
  ]);

  const nif = get(block, [
    'NIF','CIF','DNI','NIF/CIF','NIF-CIF',
    'Numero fiscal','Número fiscal',
    'Identificacion fiscal','Identificación fiscal',
    'ID fiscal','Documento','Nif','Cif'
  ]);

  const direccion = get(block, [
    'Direccion','Dirección','Dir',
    'Domicilio','Domicilio fiscal','Domicilio social',
    'Direccion fiscal','Dirección fiscal',
    'Calle','Ubicacion','Ubicación',
    'Direccion cliente','Dirección cliente',
    'Domicilio cliente','C/'
  ]);

  const emailCliente = get(block, [
    'Email cliente','EmailCliente','Email',
    'Correo','Correo electronico','Correo electrónico',
    'Mail','E-mail','Correo cliente',
    'Correo del cliente','Email del cliente'
  ]);

  const concepto = get(block, [
    'Concepto','Descripcion','Descripción',
    'Servicio','Detalle','Detalle servicio',
    'Tipo servicio','Tipo de servicio',
    'Motivo','Evento','Tipo evento',
    'Tipo de evento','Menu','Menú',
    'Celebracion','Celebración','Para'
  ]);

  const personas = getPersonas(block) || 1;

  const precioRaw = get(block, [
    'PrecioUnitario','Precio unitario',
    'Precio por persona','PrecioPersona','Precio persona',
    'Importe unitario','Importe por persona',
    'Precio por comensal','Precio comensal',
    'Precio menu','Precio menú',
    'Precio por cubierto','Precio cubierto',
    'Precio por pax','Precio pax',
    'Coste por persona','Coste persona',
    'Coste unitario','Coste por comensal',
    'Tarifa','Tarifa por persona',
    'Precio individual','Por persona',
    'Por comensal','Por cubierto',
    'Precio','Coste'
  ]);

  const importeRaw = get(block, [
    'ImporteTotal','Importe total','Importe',
    'Total servicio','Precio total',
    'Total','Coste total',
    'Importe servicio','Importe del servicio',
    'Facturar','Monto','Monto total',
    'Suma','Suma total','Valor',
    'Valor total','Precio servicio',
    'Total evento','Importe evento'
  ]);

  const fechaServicio = get(block, [
    'Fecha servicio','FechaServicio',
    'Fecha del servicio','Fecha evento',
    'Fecha del evento','Fecha',
    'Dia','Día','Dia servicio','Día servicio',
    'Dia del servicio','Día del servicio',
    'Dia evento','Día evento',
    'Cuando','Cuándo','Fecha celebracion',
    'Fecha celebración','Fecha reserva'
  ]);

  const formaPago = get(block, [
    'Forma de pago','FormaPago','Forma pago',
    'Pago','Metodo pago','Método de pago',
    'Metodo de pago','Método pago',
    'Tipo pago','Tipo de pago',
    'Como paga','Cómo paga',
    'Medio de pago','Medio pago',
    'Pagado con','Paga con','Paga por',
    'Pagado','Cobrado','Cobro'
  ]) || 'Transferencia bancaria';

  const mensajeCliente = get(block, [
    'Mensaje cliente','MensajeCliente','Mensaje',
    'Texto cliente','Nota','Notas',
    'Observaciones','Comentario','Comentarios',
    'Mensaje personalizado','Texto factura',
    'Texto para el cliente','Dedicatoria'
  ]) || `Estimado/a ${cliente},\n\nAdjunto encontrará la factura correspondiente a los servicios prestados en nuestro restaurante.\n\nQuedamos a su disposición para cualquier consulta.\n\nAtentamente,\n[Nombre del Negocio]\nTel: [Teléfono del Negocio]`;

  if (!cliente) return;

  const precioDirecto = cleanNumber(precioRaw);
  const importeTotal  = cleanNumber(importeRaw);

  let totalConIva;
  if (importeTotal > 0) {
    totalConIva = importeTotal;
  } else if (precioDirecto > 0) {
    totalConIva = precioDirecto * personas;
  } else {
    totalConIva = 0;
  }

  const baseImponible = totalConIva / 1.10;
  const iva = totalConIva - baseImponible;
  const precioUnitarioSinIva = personas > 0 ? baseImponible / personas : 0;

  const facturaData = {
    chatId,
    cliente, nif, direccion, emailCliente, concepto,
    personas,
    precioUnitario: precioUnitarioSinIva.toFixed(2),
    baseImponible: baseImponible.toFixed(2),
    iva: iva.toFixed(2),
    total: totalConIva.toFixed(2),
    fechaServicio, formaPago, mensajeCliente,
    fechaEmision: now.toLocaleDateString('es-ES')
  };

  // Guardar en staticData SIN _action para no contaminar
  staticData[String(chatId)] = {
    estado: 'WAITING_CONFIRM',
    factura: { ...facturaData }
  };

  // _action PREVIEW solo para el output, no se guarda en staticData
  facturas.push({ ...facturaData, _action: 'PREVIEW' });
});

if (facturas.length === 0) {
  return [{ json: { _action: 'ERROR', chatId, message: errorMsg } }];
}

return facturas.map(f => ({ json: f }));

