// El input viene del Sheet (Obtener Último Nº)
// Los datos de la factura vienen de Parsear Facturas
const parsearItem = $('Parsear Facturas').first().json;
const action = parsearItem._action;

// Si es CONFIRMAR, CANCELAR o ERROR → no debería llegar aquí
// pero por seguridad lo dejamos pasar
if (action === 'CONFIRMAR' || action === 'CANCELAR' || action === 'ERROR') {
  return [{ json: parsearItem }];
}

const year = new Date().getFullYear();
let nextNumber = 1;

// Las filas del Sheet vienen por $input
const rows = $input.all();

if (rows && rows.length > 0) {
  const nums = rows
    .map(r => r.json['Nº Factura'])
    .filter(n => n && String(n).trim().match(/^FAC-\d{4}-\d+$/))
    .map(n => {
      const parts = String(n).trim().split('-');
      return parseInt(parts[2]) || 0;
    })
    .filter(n => n > 0);

  if (nums.length > 0) {
    nextNumber = Math.max(...nums) + 1;
  }
}

const invoiceNumber = `FAC-${year}-${String(nextNumber).padStart(3, '0')}`;
const clienteLimpio = (parsearItem.cliente || 'cliente')
  .replace(/\s+/g,'_')
  .replace(/[^a-zA-Z0-9_]/g,'');
const fileName = `${invoiceNumber}_${clienteLimpio}.pdf`;

// Actualizar staticData con el invoiceNumber correcto
const staticData = $getWorkflowStaticData('global');
const chatId = String(parsearItem.chatId);

if (staticData[chatId]) {
  staticData[chatId].factura.invoiceNumber = invoiceNumber;
  staticData[chatId].factura.fileName = fileName;
}

return [{ json: { ...parsearItem, invoiceNumber, fileName } }];

// Los datos de la factura vienen de Parsear Facturas
// (que los tiene en el staticData recuperado al confirmar con SI)
const d = $('Parsear Facturas').item.json;

// El enlace PDF viene del nodo de Drive
const webViewLink = $('Subir PDF a Google Drive').item.json.webViewLink || '';

return [{
  json: {
    'Nº Factura': d.invoiceNumber || '',
    'Cliente': d.cliente || '',
    'NIF': d.nif || '',
    'Concepto': d.concepto || '',
    'Personas': d.personas || '',
    'Precio Unitario': d.precioUnitario || '',
    'Base Imponible': d.baseImponible || '',
    'IVA': d.iva || '',
    'Total': d.total || '',
    'Fecha Servicio': d.fechaServicio || '',
    'Fecha Emisión': d.fechaEmision || '',
    'Forma de Pago': d.formaPago || '',
    'Enlace PDF': webViewLink
  }
}];
